from collections import deque

class Solution:
    def queryFriends(self, nodes, relations, myId, maxHop):
        # 最大跳数按题意限制到 100
        hop_limit = min(int(maxHop), 100)

        # 建立用户 ID 到兴趣集合的映射
        interests = {}
        for row in nodes:
            if not row:
                continue
            uid = row[0]
            interests[uid] = set(row[1:])

        # 起始用户一定存在，直接取出它的兴趣集合
        my_interests = interests[myId]

        # 初始化邻接表，只给存在的用户建表
        graph = {uid: [] for uid in interests}

        # 建立有向图，非法关系直接忽略
        for edge in relations:
            if len(edge) < 2:
                continue
            a, b = edge[0], edge[1]
            if a in interests and b in interests:
                graph[a].append(b)

        # BFS 计算从 myId 到其他用户的最短距离
        dist = {myId: 0}
        q = deque([myId])

        while q:
            cur = q.popleft()
            cur_dist = dist[cur]

            # 已经达到最大跳数时，不再继续向外扩展
            if cur_dist == hop_limit:
                continue

            for nxt in graph.get(cur, []):
                if nxt not in dist:
                    dist[nxt] = cur_dist + 1
                    q.append(nxt)

        items = []

        # 遍历所有可达用户，筛选有共同兴趣的用户
        for uid, d in dist.items():
            if uid == myId:
                continue

            # 计算共同兴趣，并按 ASCII 码序排序
            common = sorted(my_interests & interests[uid])
            if not common:
                continue

            # 保存排序键和输出行
            items.append((d, int(uid), [uid] + common))

        # 先按最短距离排序，再按 ID 整数值排序
        items.sort(key=lambda x: (x[0], x[1]))

        # 只返回题目要求的二维数组
        return [row for _, _, row in items]
