class Solution {
    public java.util.List<java.util.List<String>> queryFriends(
            java.util.List<java.util.List<String>> nodes,
            java.util.List<java.util.List<String>> relations,
            String myId,
            int maxHop) {

        // 最大跳数按题意限制到 100
        int hopLimit = Math.min(maxHop, 100);

        // 建立用户 ID 到兴趣集合的映射
        java.util.Map<String, java.util.Set<String>> interests = new java.util.HashMap<>();
        for (java.util.List<String> row : nodes) {
            if (row.isEmpty()) {
                continue;
            }

            String uid = row.get(0);
            java.util.Set<String> set = new java.util.HashSet<>();

            for (int i = 1; i < row.size(); i++) {
                set.add(row.get(i));
            }

            interests.put(uid, set);
        }

        // 起始用户一定存在，直接取出它的兴趣集合
        java.util.Set<String> myInterests = interests.get(myId);

        // 初始化邻接表，只给存在的用户建表
        java.util.Map<String, java.util.List<String>> graph = new java.util.HashMap<>();
        for (String uid : interests.keySet()) {
            graph.put(uid, new java.util.ArrayList<>());
        }

        // 建立有向图，非法关系直接忽略
        for (java.util.List<String> edge : relations) {
            if (edge.size() < 2) {
                continue;
            }

            String a = edge.get(0);
            String b = edge.get(1);

            if (interests.containsKey(a) && interests.containsKey(b)) {
                graph.get(a).add(b);
            }
        }

        // BFS 计算从 myId 到其他用户的最短距离
        java.util.Map<String, Integer> dist = new java.util.HashMap<>();
        java.util.Queue<String> queue = new java.util.ArrayDeque<>();

        dist.put(myId, 0);
        queue.offer(myId);

        while (!queue.isEmpty()) {
            String cur = queue.poll();
            int curDist = dist.get(cur);

            // 已经达到最大跳数时，不再继续向外扩展
            if (curDist == hopLimit) {
                continue;
            }

            for (String nxt : graph.get(cur)) {
                if (!dist.containsKey(nxt)) {
                    dist.put(nxt, curDist + 1);
                    queue.offer(nxt);
                }
            }
        }

        // 用内部类保存排序键和输出行
        class Item {
            int distance;
            int id;
            java.util.List<String> row;

            Item(int distance, int id, java.util.List<String> row) {
                this.distance = distance;
                this.id = id;
                this.row = row;
            }
        }

        java.util.List<Item> items = new java.util.ArrayList<>();

        // 遍历所有可达用户，筛选有共同兴趣的用户
        for (java.util.Map.Entry<String, Integer> entry : dist.entrySet()) {
            String uid = entry.getKey();

            if (uid.equals(myId)) {
                continue;
            }

            // 计算共同兴趣
            java.util.List<String> common = new java.util.ArrayList<>();
            for (String tag : myInterests) {
                if (interests.get(uid).contains(tag)) {
                    common.add(tag);
                }
            }

            if (common.isEmpty()) {
                continue;
            }

            // 共同兴趣按 ASCII 码序排序
            java.util.Collections.sort(common);

            java.util.List<String> row = new java.util.ArrayList<>();
            row.add(uid);
            row.addAll(common);

            items.add(new Item(entry.getValue(), Integer.parseInt(uid), row));
        }

        // 先按最短距离排序，再按 ID 整数值排序
        java.util.Collections.sort(items, (a, b) -> {
            if (a.distance != b.distance) {
                return Integer.compare(a.distance, b.distance);
            }
            return Integer.compare(a.id, b.id);
        });

        // 只返回题目要求的二维数组
        java.util.List<java.util.List<String>> answer = new java.util.ArrayList<>();
        for (Item item : items) {
            answer.add(item.row);
        }

        return answer;
    }
}
