#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// 简单整数队列
typedef struct {
    int* data;
    int front, rear, capacity;
} Queue;

static Queue* qcreate(int cap) {
    Queue* q = (Queue*)malloc(sizeof(Queue));
    q->data = (int*)malloc(cap * sizeof(int));
    q->front = q->rear = 0;
    q->capacity = cap;
    return q;
}
static void qdestroy(Queue* q) { free(q->data); free(q); }
static void qpush(Queue* q, int v) { q->data[q->rear++] = v; }
static int qpop(Queue* q) { return q->data[q->front++]; }
static bool qempty(Queue* q) { return q->front == q->rear; }

// 结果项：距离、整数ID、行起止
typedef struct { int dist, id, idx, rowStart, rowLen; } Item;
static int itemCmp(const void* a, const void* b) {
    Item* x = (Item*)a; Item* y = (Item*)b;
    if (x->dist != y->dist) return x->dist - y->dist;
    return x->id - y->id;
}

// 开放寻址哈希表：ID字符串 → 数组索引
#define HASH_CAP 20011
#define HASH_EMPTY -1
typedef struct { char* key; int value; } HashEntry;
static int hashFunc(const char* s) {
    unsigned int h = 5381;
    while (*s) h = ((h << 5) + h) + (unsigned char)(*s++);
    return h % HASH_CAP;
}
static void hashInit(HashEntry* ht) {
    for (int i = 0; i < HASH_CAP; i++) { ht[i].key = NULL; ht[i].value = HASH_EMPTY; }
}
static void hashPut(HashEntry* ht, const char* key, int value) {
    int idx = hashFunc(key);
    while (ht[idx].key != NULL && ht[idx].value != HASH_EMPTY) idx = (idx + 1) % HASH_CAP;
    ht[idx].key = (char*)key; ht[idx].value = value;
}
static int hashGet(HashEntry* ht, const char* key) {
    int idx = hashFunc(key);
    while (ht[idx].key != NULL && ht[idx].value != HASH_EMPTY) {
        if (strcmp(ht[idx].key, key) == 0) return ht[idx].value;
        idx = (idx + 1) % HASH_CAP;
    }
    return HASH_EMPTY;
}
static int strCmp(const void* a, const void* b) { return strcmp(*(const char**)a, *(const char**)b); }

char*** queryFriends(char*** nodes, int nodesSize, char*** relations, int relationsSize,
                     char* myId, int maxHop, int* returnSize) {
    int hopLimit = maxHop > 100 ? 100 : maxHop;

    // 1. 构建 ID → 索引映射
    HashEntry* idToIdx = (HashEntry*)malloc(HASH_CAP * sizeof(HashEntry));
    hashInit(idToIdx);
    int* nodeIdInt = (int*)malloc(nodesSize * sizeof(int));
    for (int i = 0; i < nodesSize; i++) { hashPut(idToIdx, nodes[i][0], i); nodeIdInt[i] = atoi(nodes[i][0]); }

    // 2. 查找起始用户索引
    int myIdx = hashGet(idToIdx, myId);
    if (myIdx == HASH_EMPTY) { *returnSize = 0; free(idToIdx); free(nodeIdInt); return NULL; }

    // 3. 统计每个节点的出度
    int* outDeg = (int*)calloc(nodesSize, sizeof(int));
    for (int i = 0; i < relationsSize; i++) {
        int aIdx = hashGet(idToIdx, relations[i][0]), bIdx = hashGet(idToIdx, relations[i][1]);
        if (aIdx != HASH_EMPTY && bIdx != HASH_EMPTY) outDeg[aIdx]++;
    }

    // 4. 按出度分配邻接表
    int** adj = (int**)malloc(nodesSize * sizeof(int*));
    int* adjSz = (int*)calloc(nodesSize, sizeof(int));
    for (int i = 0; i < nodesSize; i++) adj[i] = outDeg[i] > 0 ? (int*)malloc(outDeg[i] * sizeof(int)) : NULL;
    for (int i = 0; i < relationsSize; i++) {
        int aIdx = hashGet(idToIdx, relations[i][0]), bIdx = hashGet(idToIdx, relations[i][1]);
        if (aIdx != HASH_EMPTY && bIdx != HASH_EMPTY) adj[aIdx][adjSz[aIdx]++] = bIdx;
    }
    free(outDeg);

    // 5. BFS 计算最短距离
    int* dist = (int*)malloc(nodesSize * sizeof(int));
    bool* vis = (bool*)calloc(nodesSize, sizeof(bool));
    for (int i = 0; i < nodesSize; i++) dist[i] = -1;
    Queue* q = qcreate(nodesSize + 5);
    dist[myIdx] = 0; vis[myIdx] = true; qpush(q, myIdx);
    while (!qempty(q)) {
        int cur = qpop(q), curDist = dist[cur];
        if (curDist == hopLimit) continue;
        for (int i = 0; i < adjSz[cur]; i++) {
            int nxt = adj[cur][i];
            if (!vis[nxt]) { vis[nxt] = true; dist[nxt] = curDist + 1; qpush(q, nxt); }
        }
    }

    // 6. 统计兴趣数量
    int* intCount = (int*)malloc(nodesSize * sizeof(int));
    for (int i = 0; i < nodesSize; i++) { intCount[i] = 0; while (nodes[i][intCount[i]]) intCount[i]++; intCount[i]--; }

    // 7. 收集结果：遍历可达用户，寻找共同兴趣
    int maxRows = nodesSize * 12;
    char** stringPool = (char**)malloc(maxRows * sizeof(char*));
    int poolSize = 0;
    Item* items = (Item*)malloc(nodesSize * sizeof(Item));
    int itemCnt = 0;
    char* commonBuf[11];  // 最多10个共同兴趣

    for (int uid = 0; uid < nodesSize; uid++) {
        if (uid == myIdx || dist[uid] == -1) continue;

        // 计算共同兴趣
        int cc = 0;
        for (int i = 1; i <= intCount[myIdx] && cc < 11; i++)
            for (int j = 1; j <= intCount[uid]; j++)
                if (strcmp(nodes[myIdx][i], nodes[uid][j]) == 0) { commonBuf[cc++] = nodes[myIdx][i]; break; }
        if (cc == 0) continue;

        if (cc > 1) qsort(commonBuf, cc, sizeof(char*), strCmp);

        if (poolSize + 1 + cc > maxRows) {
            maxRows += nodesSize * 2;
            stringPool = (char**)realloc(stringPool, maxRows * sizeof(char*));
        }

        items[itemCnt].dist = dist[uid]; items[itemCnt].id = nodeIdInt[uid]; items[itemCnt].idx = uid;
        items[itemCnt].rowStart = poolSize;

        // 复制用户ID字符串
        char* idStr = nodes[uid][0];
        stringPool[poolSize] = (char*)malloc(strlen(idStr) + 1);
        strcpy(stringPool[poolSize++], idStr);

        // 复制共同兴趣
        for (int i = 0; i < cc; i++) {
            stringPool[poolSize] = (char*)malloc(strlen(commonBuf[i]) + 1);
            strcpy(stringPool[poolSize++], commonBuf[i]);
        }
        items[itemCnt].rowLen = 1 + cc;
        itemCnt++;
    }

    // 8. 排序：先按距离，再按ID整数值
    qsort(items, itemCnt, sizeof(Item), itemCmp);

    // 9. 构造返回结果
    *returnSize = itemCnt;
    char*** result = itemCnt > 0 ? (char***)malloc(itemCnt * sizeof(char**)) : NULL;
    for (int i = 0; i < itemCnt; i++) {
        int len = items[i].rowLen;
        char** row = (char**)malloc((len + 1) * sizeof(char*));
        int start = items[i].rowStart;
        for (int j = 0; j < len; j++) row[j] = stringPool[start + j];
        row[len] = NULL;
        result[i] = row;
    }

    // 10. 释放临时内存
    free(intCount);
    for (int i = 0; i < nodesSize; i++) if (adj[i]) free(adj[i]);
    free(adj); free(adjSz); free(dist); free(vis);
    qdestroy(q); free(items); free(stringPool); free(idToIdx); free(nodeIdInt);
    return result;
}
